import java.util.HashMap;

public int findLucky(int[] arr) {
    HashMap<Integer, Integer> freq = new HashMap<>();

    for (int n : arr) {
        freq.put(n, freq.getOrDefault(n, 0) + 1);
    }

    int lucky = -1;
    for (int key : freq.keySet()) {
        if (key == freq.get(key)) {
            lucky = Math.max(lucky, key);
        }
    }

    return lucky;
}
